SELECT atrz_task_id, atrz_task_nm, atrz_task_desc, sys_se_cd, use_bgng_dt, use_end_dt, frst_reg_dt, frst_reg_user_id, last_chg_dt, last_chg_user_id FROM com.tn_atrz_task WHERE NOW() BETWEEN use_bgng_dt AND use_end_dt
AND sys_se_cd = #{sysSeCd}
ORDER BY atrz_task_id

SELECT COUNT(1) > 0
  FROM com.tn_atrz_task
 WHERE atrz_task_id = #{atrzTaskId}

mapper.update:
UPDATE com.tn_atrz_task
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE atrz_task_id = #{atrzTaskId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
